-- Supabase migration for Organizational Worldviews Annotations
-- Run in Supabase SQL Editor (Dashboard > SQL Editor > New query)

create table if not exists sources (
  id           text primary key,
  display_num  text not null default '',
  author       text not null default '',
  section      text not null default '',
  year         text not null default '',
  data_section text not null default '',
  data_year    text not null default '',
  data_type    text not null default '',
  citation     text not null default '',
  annotation   text not null default '',
  sort_order   integer not null default 0,
  created_at   timestamptz default now(),
  updated_at   timestamptz default now()
);

alter table sources enable row level security;
create policy "public read" on sources for select using (true);
create policy "anon insert" on sources for insert with check (true);
create policy "anon update" on sources for update using (true);
create policy "anon delete" on sources for delete using (true);

create or replace function update_updated_at()
returns trigger language plpgsql as $$
begin new.updated_at = now(); return new; end; $$;

drop trigger if exists sources_updated_at on sources;
create trigger sources_updated_at
  before update on sources
  for each row execute procedure update_updated_at();

create table if not exists keywords (
  id         uuid primary key default gen_random_uuid(),
  source_id  text references sources(id) on delete cascade,
  keyword    text not null,
  created_at timestamptz default now()
);
alter table keywords enable row level security;
create policy "public read kw" on keywords for select using (true);
create policy "anon insert kw" on keywords for insert with check (true);
create policy "anon delete kw" on keywords for delete using (true);

